mapper.select:
SELECT id, zone_key, display_name, polygon_points, map_x, map_y, color, parent_zone_key
FROM location_zones
WHERE zone_key = #{zoneKey}

mapper.update:
UPDATE location_zones
SET polygon_points = #{polygonPoints}
WHERE zone_key = #{zoneKey}

